class Solution:
    def closeStrings(self, word1: str, word2: str) -> bool:
        if len(word1) != len(word2) or set(word1) != set(word2):
            return False

        word1_map = {}
        word2_map = {}
        word1_occ = {}
        word2_occ = {}

        for i in range(len(word1)):
            word1_map[word1[i]] = word1_map.get(word1[i], 0) + 1
            word2_map[word2[i]] = word2_map.get(word2[i], 0) + 1

        for v in word1_map.values():
            word1_occ[v] = word1_occ.get(v, 0) + 1

        for v in word2_map.values():
            word2_occ[v] = word2_occ.get(v, 0) + 1

        return word1_occ == word2_occ


if __name__ == "__main__":
    s = Solution()
    print(s.closeStrings("aaaaabbcccdddeeeeffff", "aaabbbbccddeeeeefffff"))
    print(
        s.closeStrings(
            "",
            "",
        )
    )
